import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useMutation } from '@tanstack/react-query';
import { Loader2 } from 'lucide-react';
import { authService as accountService } from '@/api/auth/authService';
import { Button } from '@/shadcn/components/ui/button';
import { Alert, AlertDescription } from '@/shadcn/components/ui/alert';
import { HarmonyInput } from '@/components/ui/harmony-input';
import { useAuth } from '@/shared/AuthContext';

interface OtpProps {
  email: string;
}

export const OtpComponent = ({ email }: OtpProps) => {
  const navigate = useNavigate();
  const [code, setCode] = useState('');
  const [resolvedEmail, setResolvedEmail] = useState(email);

  // Recover email if refreshed
  useEffect(() => {
    if (!email) {
      const savedEmail = sessionStorage.getItem('otp-email');
      if (savedEmail) {
        setResolvedEmail(savedEmail);
      }
    }
  }, [email]);

  const { login } = useAuth();

  const verifyMutation = useMutation({
    mutationFn: (payload: {
      email: string;
      otp: string;
      rememberMe: boolean;
    }) => accountService.verifyOtp(payload),

    onSuccess: async (data) => {
      await login(data);
      sessionStorage.removeItem('otp-email');
      navigate('/dashboard');
    },
  });

  const onSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!resolvedEmail) {
      console.error("Email missing — cannot verify OTP.");
      return;
    }

    if (code.length !== 6) return;

    verifyMutation.mutate({
      email: resolvedEmail.trim(),
      otp: code,
      rememberMe: true,
    });
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold text-foreground mb-2">
          Verify OTP
        </h2>
        <p className="text-sm text-muted-foreground">
          We sent a code to:
          <br />
          <span className="font-bold text-primary">
            {resolvedEmail || "ERROR: NO EMAIL PROVIDED"}
          </span>
        </p>
      </div>

      {(!resolvedEmail || verifyMutation.isError) && (
        <Alert variant="destructive">
          <AlertDescription>
            {!resolvedEmail
              ? "Configuration Error: Email not found."
              : "Invalid or expired OTP."}
          </AlertDescription>
        </Alert>
      )}

      <form onSubmit={onSubmit} className="space-y-5">
        <HarmonyInput
          label="6-Digit Code"
          type="text"
          inputMode="numeric"
          maxLength={6}
          placeholder="000000"
          value={code}
          onChange={(e) => setCode(e.target.value.replace(/\D/g, ''))}
          className="text-center text-2xl tracking-[1em]"
        />

        <Button
          type="submit"
          className="w-full"
          disabled={verifyMutation.isPending || !resolvedEmail || code.length !== 6}
        >
          {verifyMutation.isPending && <Loader2 className="animate-spin" />}
          {verifyMutation.isPending ? 'Verifying...' : 'Verify & Access Dashboard'}
        </Button>
      </form>
    </div>
  );
};
